 29→/**
 30→ * Binding + additional contextual information
 31→ * Also defines equality over bindings.
 32→ * https://stackoverflow.com/questions/5453226/java-need-a-hash-map-where-one-supplies-a-function-to-do-the-hashing
 33→ */
 34→class MappableBinding(val binding: Binding, private val screen: Screen) {
 35→    val isKey: Boolean get() = binding.isKey
 36→    val isKeyCode: Boolean get() = binding.isKeyCode
 37→
 38→    override fun equals(other: Any?): Boolean {
 39→        if (this === other) {
 40→            return true
 41→        }
 42→        if (other == null || javaClass != other.javaClass) {
 43→            return false
 44→        }
 45→        val otherMappableBinding = other as MappableBinding
 46→
 47→        val otherBinding = otherMappableBinding.binding
 48→        val bindingEquals = binding.keycode == otherBinding.keycode &&
 49→            binding.unicodeCharacter == otherBinding.unicodeCharacter &&
 50→            binding.gesture == otherBinding.gesture &&
 51→            modifierEquals(otherBinding.modifierKeys)
 52→
 53→        if (!bindingEquals) {
 54→            return false
 55→        }
 56→
 57→        return screen.screenEquals(otherMappableBinding.screen)
 58→    }
 59→
 60→    override fun hashCode(): Int {
 61→        // don't include the modifierKeys or mSide
 62→        return Objects.hash(binding.keycode, binding.unicodeCharacter, binding.gesture, screen.prefix)
 63→    }
 64→
 65→    private fun modifierEquals(keys: Binding.ModifierKeys?): Boolean {
 66→        // equals allowing subclasses
 67→        val thisKeys = binding.modifierKeys
 68→        if (thisKeys === keys) {
 69→            return true
 70→        }
 71→        // one is null
 72→        return if (keys == null || thisKeys == null) {
 73→            false
 74→        } else {
 75→            (thisKeys.shiftMatches(true) == keys.shiftMatches(true) || thisKeys.shiftMatches(false) == keys.shiftMatches(false)) &&
 76→                (thisKeys.ctrlMatches(true) == keys.ctrlMatches(true) || thisKeys.ctrlMatches(false) == keys.ctrlMatches(false)) &&
