 93→    abstract class Screen private constructor(val prefix: Char) {
 94→        abstract fun toPreferenceString(binding: Binding): String?
 95→        abstract fun toDisplayString(context: Context, binding: Binding): String
 96→        abstract fun screenEquals(otherScreen: Screen): Boolean
 97→
 98→        class Reviewer(val side: CardSide) : Screen('r') {
 99→            override fun toPreferenceString(binding: Binding): String? {
100→                if (!binding.isValid) {
101→                    return null
102→                }
103→                val s = StringBuilder()
104→                s.append(prefix)
105→                s.append(binding.toString())
106→                // don't serialise problematic bindings
107→                if (s.isEmpty()) {
108→                    return null
109→                }
110→                when (side) {
111→                    CardSide.QUESTION -> s.append('0')
112→                    CardSide.ANSWER -> s.append('1')
113→                    CardSide.BOTH -> s.append('2')
114→                }
115→                return s.toString()
116→            }
117→
118→            override fun toDisplayString(context: Context, binding: Binding): String {
119→                val formatString = when (side) {
120→                    CardSide.QUESTION -> context.getString(R.string.display_binding_card_side_question)
121→                    CardSide.ANSWER -> context.getString(R.string.display_binding_card_side_answer)
122→                    else -> context.getString(R.string.display_binding_card_side_both) // intentionally no prefix
123→                }
124→                return String.format(formatString, binding.toDisplayString(context))
125→            }
126→
127→            override fun screenEquals(otherScreen: Screen): Boolean {
128→                val other: Reviewer = otherScreen as? Reviewer ?: return false
129→
130→                return side === CardSide.BOTH ||
131→                    other.side === CardSide.BOTH ||
132→                    side === other.side
133→            }
134→
135→            companion object {
136→                @CheckResult
137→                fun fromGesture(b: Binding): MappableBinding = MappableBinding(b, Reviewer(CardSide.BOTH))
138→                fun fromString(s: String): MappableBinding {
139→                    val binding = s.substring(0, s.length - 1)
140→                    val b = Binding.fromString(binding)
141→                    val side = when (s[s.length - 1]) {
142→                        '0' -> CardSide.QUESTION
143→                        '1' -> CardSide.ANSWER
144→                        else -> CardSide.BOTH
145→                    }
146→                    return MappableBinding(b, Reviewer(side))
147→                }
148→            }
149→        }
150→    }
151→
152→    /** the serialisation version */
153→    enum class Version {
154→        ONE
155→    }
156→
157→    companion object {
158→        const val PREF_SEPARATOR = '|'
159→
160→        @CheckResult
161→        fun fromGesture(gesture: Gesture): MappableBinding = MappableBinding(Binding(gesture), Screen.Reviewer(CardSide.BOTH))
162→
163→        @CheckResult
164→        fun fromGestureBinding(b: Binding): MappableBinding = MappableBinding(b, Screen.Reviewer(CardSide.BOTH))
165→
166→        @CheckResult
167→        fun List<MappableBinding>.toPreferenceString(): String = this.mapNotNull { it.toPreferenceString() }
168→            .joinToString(prefix = "1/", separator = PREF_SEPARATOR.toString())
169→
170→        @Suppress("UNUSED_PARAMETER")
171→        @CheckResult
172→        fun fromString(s: String, v: Version = Version.ONE): MappableBinding? {
173→            if (s.isEmpty()) {
174→                return null
175→            }
176→            return try {
177→                // the prefix of the serialized
178→                when (s[0]) {
179→                    'r' -> Screen.Reviewer.fromString(s.substring(1))
180→                    else -> null
181→                }
182→            } catch (e: Exception) {
183→                Timber.w(e, "failed to deserialize binding")
184→                null
185→            }
186→        }
187→
188→        @CheckResult
189→        fun fromPreferenceString(string: String?): MutableList<MappableBinding> {
190→            if (string.isNullOrEmpty()) return ArrayList()
191→            try {
192→                val version = string.takeWhile { x -> x != '/' }
193→                val remainder = string.substring(version.length + 1) // skip the /
194→                if (version != "1") {
195→                    Timber.w("cannot handle version '$version'")
196→                    return ArrayList()
197→                }
198→                return remainder.split(PREF_SEPARATOR).mapNotNull { fromString(it) }.toMutableList()
199→            } catch (e: Exception) {
200→                Timber.w(e, "Failed to deserialize preference")
201→                return ArrayList()
202→            }
203→        }
204→
205→        @CheckResult
206→        fun fromPreference(prefs: SharedPreferences, command: ViewerCommand): MutableList<MappableBinding> {
207→            val value = prefs.getString(command.preferenceKey, null) ?: return command.defaultValue.toMutableList()
208→            return fromPreferenceString(value)
209→        }
210→
211→        @CheckResult
212→        fun allMappings(prefs: SharedPreferences): MutableList<Pair<ViewerCommand, MutableList<MappableBinding>>> {
213→            return ViewerCommand.values().map {
214→                Pair(it, fromPreference(prefs, it))
215→            }.toMutableList()
216→        }
217→    }
218→}
